-- First, delete quiz questions for these lessons
DELETE FROM quiz_questions WHERE lesson_id IN (
  SELECT id FROM lessons WHERE (course_id = 4 AND `order` IN (8, 9)) OR (course_id = 6 AND `order` = 9)
);

-- Delete the lessons
DELETE FROM lessons WHERE (course_id = 4 AND `order` IN (8, 9)) OR (course_id = 6 AND `order` = 9);

-- Update course totals
UPDATE courses SET total_lessons = 7 WHERE id = 4;
UPDATE courses SET total_lessons = 8 WHERE id = 6;

